// src/components/Navbar.js
import React, { useState, useEffect, useRef } from "react";
import { Link, useNavigate } from "react-router-dom";
import { Search, X, Menu } from "lucide-react";
import logo from "../assets/logo.png";

const pages = [
  { name: "Home", path: "/" },
  { name: "About", path: "/about" },
  { name: "Domains", path: "/domains" },
  { name: "Vision", path: "/vision" },
  { name: "Purpose", path: "/purpose" },
  { name: "Team", path: "/team" },
  { name: "Careers", path: "/careers" },
  { name: "Contact", path: "/contact" },
];

function Navbar() {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [query, setQuery] = useState("");
  const [results, setResults] = useState([]);
  const [activeIndex, setActiveIndex] = useState(0);
  const inputRef = useRef(null);
  const navigate = useNavigate();

  // Focus input when search opens
  useEffect(() => {
    if (isSearchOpen) {
      setActiveIndex(0);
      inputRef.current?.focus();
    }
  }, [isSearchOpen]);

  // Close search or menu with ESC
  useEffect(() => {
    const handleEsc = (e) => {
      if (e.key === "Escape") {
        setIsSearchOpen(false);
        setIsMenuOpen(false);
      }
    };
    window.addEventListener("keydown", handleEsc);
    return () => window.removeEventListener("keydown", handleEsc);
  }, []);

  // Filter pages
  useEffect(() => {
    if (query.trim() === "") setResults([]);
    else
      setResults(
        pages.filter((p) =>
          p.name.toLowerCase().includes(query.toLowerCase())
        )
      );
  }, [query]);

  const handleSearchSelect = (path) => {
    navigate(path);
    setIsSearchOpen(false);
    setQuery("");
  };

  // Keyboard navigation inside search results
  const handleKeyDown = (e) => {
    if (!results.length) return;

    if (e.key === "ArrowDown") {
      setActiveIndex((prev) => (prev + 1) % results.length);
    } else if (e.key === "ArrowUp") {
      setActiveIndex((prev) =>
        prev === 0 ? results.length - 1 : prev - 1
      );
    } else if (e.key === "Enter") {
      handleSearchSelect(results[activeIndex].path);
    }
  };

  return (
    <nav className="w-full bg-black text-white fixed top-0 z-50 shadow-md">
      <div className="max-w-7xl mx-auto px-6 md:px-10 flex justify-between items-center h-16">
        {/* Logo */}
        <div className="flex items-center space-x-2">
          <img src={logo} alt="Godemar Logo" className="w-10 h-10" />
          <span className="font-bold text-xl">Godemar’s Empire</span>
        </div>

        {/* Desktop Links */}
        <div className="hidden md:flex items-center space-x-6">
          {pages.map((page) => (
            <Link
              key={page.path}
              to={page.path}
              className="hover:text-yellow-500 focus:outline focus:outline-2 focus:outline-yellow-500 rounded"
            >
              {page.name}
            </Link>
          ))}
          <button
            onClick={() => setIsSearchOpen(true)}
            className="ml-2 p-2 hover:text-yellow-500 focus:outline focus:outline-2 focus:outline-yellow-500 rounded"
            aria-label="Open search"
          >
            <Search size={20} />
          </button>
        </div>

        {/* Mobile Hamburger */}
        <div className="md:hidden flex items-center">
          <button
            onClick={() => setIsSearchOpen(true)}
            className="mr-2 p-2"
            aria-label="Open search"
          >
            <Search size={20} />
          </button>
          <button
            onClick={() => setIsMenuOpen(!isMenuOpen)}
            aria-label="Toggle menu"
          >
            {isMenuOpen ? <X size={24} /> : <Menu size={24} />}
          </button>
        </div>
      </div>

      {/* Mobile Menu */}
      {isMenuOpen && (
        <div className="md:hidden bg-black text-white px-6 py-4 space-y-4">
          <div className="flex justify-between items-center">
            <span className="font-bold">Menu</span>
            <button
              onClick={() => setIsMenuOpen(false)}
              className="p-2 hover:text-red-500 focus:outline focus:outline-2 focus:outline-red-500 rounded"
              aria-label="Close menu"
            >
              <X size={20} />
            </button>
          </div>
          {pages.map((page) => (
            <Link
              key={page.path}
              to={page.path}
              onClick={() => setIsMenuOpen(false)}
              className="block hover:text-yellow-500 focus:outline focus:outline-2 focus:outline-yellow-500 rounded"
            >
              {page.name}
            </Link>
          ))}
        </div>
      )}

      {/* Search Overlay */}
      {isSearchOpen && (
        <div className="fixed inset-0 bg-black bg-opacity-80 flex justify-center items-start pt-20 z-50">
          <div className="relative w-11/12 md:w-1/3 bg-white dark:bg-gray-900 rounded-xl shadow-lg p-4">
            <input
              ref={inputRef}
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder="Search pages..."
              className="w-full px-4 py-3 rounded-lg border border-gray-300 dark:border-gray-700 focus:outline-none focus:ring-2 focus:ring-yellow-500 dark:bg-gray-800 dark:text-white"
              aria-label="Search pages"
            />
            <button
              onClick={() => setIsSearchOpen(false)}
              className="absolute top-2 right-2 text-gray-600 dark:text-gray-300 hover:text-red-500 focus:outline focus:outline-2 focus:outline-red-500 rounded"
              aria-label="Close search"
            >
              <X size={24} />
            </button>

            {results.length > 0 && (
              <ul className="mt-4 max-h-64 overflow-y-auto">
                {results.map((page, index) => (
                  <li key={page.path}>
                    <button
                      onClick={() => handleSearchSelect(page.path)}
                      className={`w-full text-left block px-4 py-2 rounded ${
                        index === activeIndex
                          ? "bg-yellow-100 dark:bg-gray-700"
                          : "hover:bg-yellow-100 dark:hover:bg-gray-700"
                      }`}
                      tabIndex={0}
                    >
                      {page.name}
                    </button>
                  </li>
                ))}
              </ul>
            )}
          </div>
        </div>
      )}
    </nav>
  );
}

export default Navbar;
